#!/usr/bin/env bash
# Submit Paris rknot probe to Cloud Build (minimal source tarball).
# Usage:
#   ./scripts/submit-paris-probe-cloud.sh                    # default: --max-layers=8
#   ./scripts/submit-paris-probe-cloud.sh 20               # --max-layers=20
#   ./scripts/submit-paris-probe-cloud.sh 40 --sync        # wait for completion
#
# Optional: point Cloud Build at a variant rknot on R2 (default in yaml is models/llama-70b.rknot).
#   PARIS_RKNOT_R2_KEY=models/llama-70b-precise.rknot ./scripts/submit-paris-probe-cloud.sh 8
#
# Optional: also run `--dense-only` in parallel (same layer cap / tokens) for baseline ‖residual‖∞.
#   PARIS_RUN_DENSE_BASELINE=1 ./scripts/submit-paris-probe-cloud.sh 8
#
# Optional: run verify-rknot in the same build (`_VERIFY_MAX_LAYERS` defaults to 8).
#   PARIS_RUN_VERIFY_RKNOT=1 PARIS_VERIFY_MAX_LAYERS=12 ./scripts/submit-paris-probe-cloud.sh 8
# Optional verify scope: standing (default) or full.
#   PARIS_RUN_VERIFY_RKNOT=1 PARIS_VERIFY_SCOPE=full ./scripts/submit-paris-probe-cloud.sh 8
#
# Optional: stderr L3+L10 residual samples in paris-probe (matches paris-probe-rknot KERNEL_DEBUG).
#   PARIS_KERNEL_DEBUG=1 ./scripts/submit-paris-probe-cloud.sh 8
# L3-only sample without paying for L4–L7: cap 4 includes L3; L10 line appears only when cap reaches layer 10 (e.g. 11+).
#   PARIS_KERNEL_DEBUG=1 PARIS_RKNOT_R2_KEY=models/llama-70b-precise.rknot ./scripts/submit-paris-probe-cloud.sh 4
#
# Optional: dump per-layer last-token residuals from both probe paths and run a
# paris-residual-diff step (per-layer cosine sim + L2 + L∞). Requires the dense
# baseline so both dumps exist.
#   PARIS_DUMP_RESIDUALS=1 PARIS_RUN_DENSE_BASELINE=1 ./scripts/submit-paris-probe-cloud.sh 80
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DI_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"
GNOSIS_ROOT="$(cd "${DI_ROOT}/.." && pwd)"
OPEN_SOURCE="$(cd "${GNOSIS_ROOT}/.." && pwd)"
BITWISE="${OPEN_SOURCE}/bitwise"
GNOSIS_FRF="${GNOSIS_ROOT}/gnosis-frf"
RTL_BRIDGE="${GNOSIS_ROOT}/rtl-bridge"
DI_ROOT="${DI_ROOT}"
for d in "${BITWISE}" "${GNOSIS_FRF}" "${RTL_BRIDGE}" "${DI_ROOT}"; do
  if [[ ! -d "${d}" ]]; then
    echo "submit-paris-probe-cloud.sh: missing directory: ${d}" >&2
    exit 1
  fi
done
if ! command -v rsync >/dev/null 2>&1; then
  echo "submit-paris-probe-cloud.sh: rsync is required" >&2
  exit 1
fi

TMP="$(mktemp -d)"
cleanup() {
  rm -rf "${TMP}"
}
trap cleanup EXIT

mkdir -p "${TMP}/gnosis"
# Layout must match Cargo.toml path deps:
#   gnosis-frf  -> ../gnosis-frf
#   bitwise     -> ../../bitwise
rsync -a \
  --exclude=target \
  --exclude=.git \
  --exclude=datasets \
  "${BITWISE}/" "${TMP}/bitwise/"
rsync -a \
  --exclude=target \
  --exclude=.git \
  "${GNOSIS_FRF}/" "${TMP}/gnosis/gnosis-frf/"
rsync -a \
  --exclude=target \
  --exclude=.git \
  "${GNOSIS_ROOT}/rtl-bridge/" "${TMP}/gnosis/rtl-bridge/"
rsync -a \
  --exclude=target \
  --exclude=.git \
  "${DI_ROOT}/" "${TMP}/gnosis/distributed-inference/"

if [[ ! -f "${TMP}/gnosis/distributed-inference/cloudbuild-paris-probe.yaml" ]]; then
  echo "submit-paris-probe-cloud.sh: missing cloudbuild-paris-probe.yaml after rsync" >&2
  exit 1
fi

cd "${TMP}"
LAYERS="${1:-8}"
SYNC="${2:-}"
SUBST="_MAX_LAYERS_FLAG=--max-layers=${LAYERS}"
if [[ -n "${PARIS_RKNOT_R2_KEY:-}" ]]; then
  SUBST="${SUBST},_RKNOT_R2_KEY=${PARIS_RKNOT_R2_KEY}"
fi
if [[ "${PARIS_RUN_DENSE_BASELINE:-0}" == "1" ]]; then
  SUBST="${SUBST},_RUN_DENSE_BASELINE=1"
fi
if [[ "${PARIS_RUN_VERIFY_RKNOT:-0}" == "1" ]]; then
  SUBST="${SUBST},_RUN_VERIFY_RKNOT=1"
  SUBST="${SUBST},_VERIFY_MAX_LAYERS=${PARIS_VERIFY_MAX_LAYERS:-8}"
  SUBST="${SUBST},_VERIFY_SCOPE=${PARIS_VERIFY_SCOPE:-standing}"
fi
if [[ "${PARIS_KERNEL_DEBUG:-0}" == "1" ]]; then
  SUBST="${SUBST},_PARIS_KERNEL_DEBUG=1"
fi
if [[ "${PARIS_DUMP_RESIDUALS:-0}" == "1" ]]; then
  SUBST="${SUBST},_DUMP_RESIDUALS=1"
fi
if [[ "${PARIS_FIDELITY_CHECK:-0}" == "1" ]]; then
  SUBST="${SUBST},_FIDELITY_CHECK=1"
fi
CMD=(gcloud builds submit --config=gnosis/distributed-inference/cloudbuild-paris-probe.yaml "--substitutions=${SUBST}" .)
if [[ "${SYNC}" != "--sync" ]]; then
  CMD+=(--async)
fi
echo "Running: ${CMD[*]}"
"${CMD[@]}"
